   878	    ///     // further checks
   879	    ///   } else {
   880	    ///     return 1;
   881	    ///   }
   882	    /// }
   883	    /// ```
   884	    ///
   885	    /// In this map we store the name a variable is bound to in the current
   886	    /// scope. For example here we know that `wibble.0` is bound to the name
